import { useState, useEffect, useCallback } from "react";
import { ethers } from "ethers";
import { FLOWARC_ADDRESS } from "../contracts/abis";

function EmployerDashboard({ flowArc, usdc, address, isEmployer, setIsEmployer, notify }) {
  const [companyName, setCompanyName]   = useState("");
  const [balance, setBalance]           = useState("0");
  const [depositAmt, setDepositAmt]     = useState("");
  const [withdrawAmt, setWithdrawAmt]   = useState("");
  const [workers, setWorkers]           = useState([]);
  const [workerAddr, setWorkerAddr]     = useState("");
  const [workerName, setWorkerName]     = useState("");
  const [workerSalary, setWorkerSalary] = useState("");
  const [loading, setLoading]           = useState(false);
  const [usdcBalance, setUsdcBalance]   = useState("0");

  const loadData = useCallback(async () => {
    if (!flowArc || !address) return;
    try {
      const emp = await flowArc.employers(address);
      if (emp.registered) {
        setBalance(ethers.utils.formatUnits(emp.balance, 6));
        const addrs = await flowArc.getEmployerWorkers(address);
        const data  = await Promise.all(addrs.map(async (a) => {
          const d = await flowArc.getWorkerDetails(address, a);
          return {
            address: a, name: d.name, active: d.active,
            earned: ethers.utils.formatUnits(d.earned, 6),
            monthlySalary: ethers.utils.formatUnits(d.salaryPerSecond.mul(30 * 24 * 3600), 6)
          };
        }));
        setWorkers(data);
      }
      if (usdc) {
        const b = await usdc.balanceOf(address);
        setUsdcBalance(ethers.utils.formatUnits(b, 6));
      }
    } catch (e) { console.error(e); }
  }, [flowArc, usdc, address]);

  useEffect(() => {
    loadData();
    const i = setInterval(loadData, 10000);
    return () => clearInterval(i);
  }, [loadData]);

  const registerEmployer = async () => {
    if (!companyName) return notify("Enter company name", "error");
    setLoading(true);
    try {
      const tx = await flowArc.registerEmployer(companyName);
      await tx.wait();
      setIsEmployer(true);
      notify(`"${companyName}" registered!`);
      loadData();
    } catch (e) { notify(e.message, "error"); }
    setLoading(false);
  };

  const depositFunds = async () => {
    if (!depositAmt) return notify("Enter amount", "error");
    setLoading(true);
    try {
      const amount = ethers.utils.parseUnits(depositAmt, 6);
      const allowance = await usdc.allowance(address, FLOWARC_ADDRESS);
      if (allowance.lt(amount)) {
        const t = await usdc.approve(FLOWARC_ADDRESS, ethers.constants.MaxUint256);
        await t.wait();
      }
      const tx = await flowArc.depositFunds(amount);
      await tx.wait();
      notify(`Deposited ${depositAmt} USDC!`);
      setDepositAmt("");
      loadData();
    } catch (e) { notify(e.message, "error"); }
    setLoading(false);
  };

  const withdrawFunds = async () => {
    if (!withdrawAmt) return notify("Enter amount", "error");
    setLoading(true);
    try {
      const tx = await flowArc.withdrawFunds(ethers.utils.parseUnits(withdrawAmt, 6));
      await tx.wait();
      notify(`Withdrawn ${withdrawAmt} USDC!`);
      setWithdrawAmt("");
      loadData();
    } catch (e) { notify(e.message, "error"); }
    setLoading(false);
  };

  const addWorker = async () => {
    if (!workerAddr || !workerName || !workerSalary) return notify("Fill all fields", "error");
    setLoading(true);
    try {
      const tx = await flowArc.addWorker(workerAddr, workerName, ethers.utils.parseUnits(workerSalary, 6));
      await tx.wait();
      notify(`"${workerName}" added!`);
      setWorkerAddr(""); setWorkerName(""); setWorkerSalary("");
      loadData();
    } catch (e) { notify(e.message, "error"); }
    setLoading(false);
  };

  const removeWorker = async (wa) => {
    setLoading(true);
    try {
      const tx = await flowArc.removeWorker(wa);
      await tx.wait();
      notify("Worker removed!");
      loadData();
    } catch (e) { notify(e.message, "error"); }
    setLoading(false);
  };

  if (!isEmployer) return (
    <div className="register-card">
      <div className="register-icon">🏢</div>
      <div className="register-title">Register Your Company</div>
      <div className="register-sub">Set up your payroll vault to start streaming USDC salaries to your workers onchain.</div>
      <input className="inp" placeholder="Company Name" value={companyName} onChange={e => setCompanyName(e.target.value)} />
      <button className="btn-gold" onClick={registerEmployer} disabled={loading}>
        {loading ? "Registering..." : "Register Company →"}
      </button>
    </div>
  );

  return (
    <div>
      <div className="balance-card">
        <div className="bal-item">
          <div className="bal-label">Payroll Vault</div>
          <div className="bal-value">{parseFloat(balance).toFixed(2)}<span className="unit">USDC</span></div>
        </div>
        <div className="bal-divider" />
        <div className="bal-item">
          <div className="bal-label">Wallet Balance</div>
          <div className="bal-value">{parseFloat(usdcBalance).toFixed(2)}<span className="unit">USDC</span></div>
        </div>
        <div className="bal-divider" />
        <div className="bal-item">
          <div className="bal-label">Active Workers</div>
          <div className="bal-value">{workers.filter(w => w.active).length}</div>
        </div>
      </div>

      <div className="two-col">
        <div className="card">
          <div className="card-title">💰 Deposit USDC</div>
          <div className="card-sub">Fund your payroll vault</div>
          <input className="inp" placeholder="Amount" type="number" value={depositAmt} onChange={e => setDepositAmt(e.target.value)} />
          <button className="btn-gold" onClick={depositFunds} disabled={loading}>Deposit</button>
        </div>
        <div className="card">
          <div className="card-title">🏦 Withdraw USDC</div>
          <div className="card-sub">Withdraw from vault</div>
          <input className="inp" placeholder="Amount" type="number" value={withdrawAmt} onChange={e => setWithdrawAmt(e.target.value)} />
          <button className="btn-danger" onClick={withdrawFunds} disabled={loading}>Withdraw</button>
        </div>
      </div>

      <div className="card">
        <div className="card-title">➕ Add Worker</div>
        <div className="card-sub">Register a new worker to your payroll</div>
        <input className="inp" placeholder="Wallet Address (0x...)" value={workerAddr} onChange={e => setWorkerAddr(e.target.value)} />
        <input className="inp" placeholder="Worker Name" value={workerName} onChange={e => setWorkerName(e.target.value)} />
        <input className="inp" placeholder="Monthly Salary (USDC)" type="number" value={workerSalary} onChange={e => setWorkerSalary(e.target.value)} />
        <button className="btn-gold" onClick={addWorker} disabled={loading}>{loading ? "Adding..." : "Add Worker →"}</button>
      </div>

      <div className="card">
        <div className="card-title">👷 Workers</div>
        {workers.length === 0 && <div className="empty">No workers added yet</div>}
        {workers.map(w => (
          <div key={w.address} className="worker-row">
            <div>
              <div className="worker-name">
                {w.name}
                {!w.active && <span className="badge-inactive">Inactive</span>}
              </div>
              <div className="worker-addr">{w.address.slice(0,10)}...{w.address.slice(-6)}</div>
              <div className="worker-salary">Monthly: {parseFloat(w.monthlySalary).toFixed(2)} USDC</div>
            </div>
            <div style={{textAlign:"right"}}>
              <div className="worker-earned">Earned: {parseFloat(w.earned).toFixed(4)} USDC</div>
              {w.active && (
                <button className="btn-remove" onClick={() => removeWorker(w.address)} disabled={loading}>
                  Remove
                </button>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default EmployerDashboard;
